import { GameConfig, CarModel, LevelConfig } from '../types';

// We assume Matter is loaded via CDN globally
const Matter = (window as any).Matter;

export interface Decoration {
  x: number;
  y: number;
  angle: number;
  scale: number;
  type: number; // 0-2: Grass, 3: Lamp, 4: Fence, 5: Finish Line Flag
}

export interface Cloud {
  x: number;
  y: number;
  scale: number;
  speedFactor: number; 
  textureId: number;
}

export interface TerrainChunk {
  composite: any;
  pathData: {x: number, y: number}[];
  decorations: Decoration[];
  coinBodies: any[];
  fuelBodies: any[];
  islandBodies: any[];
  rampBodies: any[];
  obstacleBodies: any[];
  boulderBodies: any[];
  finishLineBody?: any;
  endY: number;
  endGlobalIndex: number;
  nextSegmentsSinceFuel: number; 
  id: number;
}

export const createEngine = (config: GameConfig) => {
  const engine = Matter.Engine.create();
  engine.gravity.y = config.GRAVITY;

  // High iterations for rigid constraints
  engine.positionIterations = 10;
  engine.velocityIterations = 10;

  return engine;
};

export const createCar = (x: number, y: number, carConfig: CarModel, gameConfig: GameConfig) => {
  // Use car specific config if available, fallback to global config
  const CAR_WIDTH = carConfig.width || gameConfig.CAR_WIDTH;
  const CAR_HEIGHT = carConfig.height || gameConfig.CAR_HEIGHT;
  const WHEEL_SIZE = carConfig.wheelSize || gameConfig.WHEEL_SIZE;

  const group = Matter.Body.nextGroup(true);

  // 1. Chassis
  const chassis = Matter.Bodies.rectangle(x, y, CAR_WIDTH, CAR_HEIGHT, {
    collisionFilter: { group: group },
    density: carConfig.density, 
    friction: 0.3,
    label: 'chassis',
    render: { fillStyle: carConfig.bodyColor },
    chamfer: { radius: 15 } 
  });

  // Calculate offsets for vertical alignment
  // Positions the wheel anchor point near the edge of the chassis
  const wheelOffsetX = -CAR_WIDTH / 2 + WHEEL_SIZE;
  const wheelOffsetY = CAR_HEIGHT / 2;

  // 2. Wheels
  const wheelOptions = {
    collisionFilter: { group: group },
    friction: carConfig.friction,       
    frictionStatic: 1.5, 
    density: 0.01,  // Reduced density to minimize wheel inertia/swing     
    restitution: 0.2,    
    render: { fillStyle: 'black' }
  };

  // Align wheels vertically with suspension points to prevent horizontal swing at rest
  const wheelA = Matter.Bodies.circle(x + wheelOffsetX, y + wheelOffsetY, WHEEL_SIZE, {
    ...wheelOptions,
    label: 'wheelBack'
  });

  const wheelB = Matter.Bodies.circle(x - wheelOffsetX, y + wheelOffsetY, WHEEL_SIZE, {
    ...wheelOptions,
    label: 'wheelFront'
  });

  // 3. Suspension
  // Ultra-rigid settings to prevent side-to-side (pendulum) movement
  const suspensionStiffness = 1.0; 
  const suspensionDamping = 0.6;   
  const suspensionLength = 7; // Shortened slightly for tighter control

  const axelA = Matter.Constraint.create({
    bodyA: chassis,
    bodyB: wheelA,
    pointA: { x: wheelOffsetX, y: wheelOffsetY },
    pointB: { x: 0, y: 0 },
    stiffness: suspensionStiffness,
    damping: suspensionDamping,
    length: suspensionLength,
    render: { visible: false }
  });

  const axelB = Matter.Constraint.create({
    bodyA: chassis,
    bodyB: wheelB,
    pointA: { x: -wheelOffsetX, y: wheelOffsetY },
    pointB: { x: 0, y: 0 },
    stiffness: suspensionStiffness,
    damping: suspensionDamping,
    length: suspensionLength,
    render: { visible: false }
  });

  return Matter.Composite.create({
    bodies: [chassis, wheelA, wheelB],
    constraints: [axelA, axelB],
    label: 'car'
  });
};

export const createWall = (x: number) => {
    return Matter.Bodies.rectangle(x, -1000, 100, 5000, {
        isStatic: true,
        label: 'wall',
        render: { visible: false }
    });
};

/**
 * Calculates the noise/height for a specific index. 
 * Supports different logic based on map type.
 */
export const getTerrainNoise = (globalIndex: number, config: GameConfig, mapType: string = 'earth'): number => {
    const baseHeight = 70;

    // Standard Logic
    const nx = globalIndex * config.TERRAIN_NOISE_FREQ_1;
    const nzOsc = Math.sin(nx * 0.2);
    let amp = 0.1;
    if (nzOsc > 0.3) amp = 1.0;
    else if (nzOsc >= -0.3) amp = 0.1 + ((nzOsc+0.3)/0.6)*0.9;

    const nPrimary = Math.sin(nx) * config.TERRAIN_AMP_1;
    const nSecondary = Math.cos(globalIndex * config.TERRAIN_NOISE_FREQ_2) * config.TERRAIN_AMP_2;
    const nRumble = Math.sin(globalIndex * config.TERRAIN_NOISE_FREQ_3) * config.TERRAIN_AMP_3;

    const difficultyMultiplier = Math.min(2.5, 1 + (globalIndex * 0.001));

    return (nPrimary + nSecondary + nRumble) * amp * difficultyMultiplier * baseHeight;
};

export const generateTerrainChunk = (
    chunkId: number,
    startX: number, 
    startY: number, 
    startGlobalIndex: number, 
    length: number,
    isNight: boolean,
    config: GameConfig,
    mapType: string = 'earth',
    startSegmentsSinceFuel: number = 0,
    levelTargetDistance: number | null = null
): TerrainChunk => {
  const { TERRAIN_SEGMENT_WIDTH, COIN_SIZE, FUEL_CAN_SIZE, LAMP_SPACING } = config;
  const segments = Math.floor(length / TERRAIN_SEGMENT_WIDTH);

  const groundDepth = 800; 
  const pathPoints = []; 
  const decorations: Decoration[] = [];
  const coinBodies: any[] = [];
  const fuelBodies: any[] = [];
  const islandBodies: any[] = [];
  const rampBodies: any[] = [];
  const obstacleBodies: any[] = [];
  const boulderBodies: any[] = [];
  let finishLineBody = null;

  pathPoints.push({ x: startX, y: startY });       

  let currentX = startX;
  let currentY = startY;
  let globalIndex = startGlobalIndex;
  let lastLampX = startX;
  let coinStreak = 0;
  let segmentsSinceFuel = startSegmentsSinceFuel;

  // Track previous segments to ensure we don't spam hazards
  let segmentsSinceIsland = 0;
  let segmentsSinceRamp = 0;
  let segmentsSinceFeature = 0;

  let finishLineGenerated = false;

  for (let i = 0; i < segments; i++) {
    const segmentWidth = TERRAIN_SEGMENT_WIDTH;
    const prevX = currentX;
    const prevY = currentY;

    currentX += segmentWidth;
    globalIndex++;
    segmentsSinceFuel++;
    segmentsSinceIsland++;
    segmentsSinceRamp++;
    segmentsSinceFeature++;

    // Check if we passed level target
    if (levelTargetDistance !== null && currentX >= (200 + levelTargetDistance) && !finishLineGenerated) {
        // Flatten terrain for finish line
        const noisePrev = getTerrainNoise(globalIndex - 1, config, mapType);
        const noiseCurrent = noisePrev; // Flat
        const dy = -(noiseCurrent - noisePrev);
        currentY = prevY + dy;

        // Add finish line object
        finishLineGenerated = true;
        finishLineBody = Matter.Bodies.rectangle(currentX, currentY - 200, 20, 400, {
            isSensor: true,
            isStatic: true,
            label: 'finishLine',
            render: { visible: false }
        });

        // Add visual decoration for finish line
        decorations.push({
            x: currentX,
            y: currentY,
            angle: 0,
            scale: 1,
            type: 5 // Finish Line Type
        });
    } else {
        const noiseCurrent = getTerrainNoise(globalIndex, config, mapType);
        const noisePrev = getTerrainNoise(globalIndex - 1, config, mapType);
        const dy = -(noiseCurrent - noisePrev); 
        currentY = prevY + dy;
    }

    pathPoints.push({ x: currentX, y: currentY });

    // --- Analysis for features ---
    const angle = Math.atan2(currentY - prevY, currentX - prevX);
    const slopeFactor = 1 - Math.min(Math.abs(Math.sin(angle)), 0.8);
    const isFlatEnough = slopeFactor > 0.85; 
    let featurePlaced = false;

    // Skip obstacles near finish line
    if (finishLineGenerated) continue;

    // --- Special Map Features (Mystical Removed) ---
    // Rolling Boulders (Common in Moon, Rare elsewhere)
    const boulderChance = mapType === 'moon' ? 0.08 : 0.02;
    if (!featurePlaced && Math.random() < boulderChance && segmentsSinceFeature > 15) {
        const r = 25 + Math.random() * 15;
        const bx = currentX;
        const by = currentY - 200; // Drop from sky

        const boulder = Matter.Bodies.circle(bx, by, r, {
            density: 0.01, // Heavy
            friction: 0.5,
            restitution: 0.2,
            label: 'obstacle',
            render: { visible: false }
        });
        boulderBodies.push(boulder);
        segmentsSinceFeature = 0;
        featurePlaced = true;
    }

    // JUMP RAMPS
    if (!featurePlaced && Math.random() < 0.05 && isFlatEnough && segmentsSinceIsland > 5 && segmentsSinceRamp > 25) {
        const rampType = Math.random(); 
        let rampWidth, rampHeight, vertices;

        if (rampType < 0.5) {
            // Standard Wedge
            rampWidth = 300 + Math.random() * 100;
            rampHeight = 100 + Math.random() * 40;
            vertices = [
                { x: 0, y: rampHeight },        
                { x: rampWidth, y: rampHeight }, 
                { x: rampWidth, y: 0 }           
            ];
        } else {
            // Steep Kicker
            rampWidth = 150 + Math.random() * 50;
            rampHeight = 120 + Math.random() * 30;
            vertices = [
                { x: 0, y: rampHeight },        
                { x: rampWidth, y: rampHeight }, 
                { x: rampWidth, y: -20 } 
            ];
        }

        const rampX = currentX + rampWidth / 2;
        const rampY = currentY - rampHeight / 2;

        const ramp = Matter.Bodies.fromVertices(rampX, rampY, [vertices], {
            isStatic: true,
            friction: 1.0,
            label: 'ground',
            render: { visible: false }
        });

        if (ramp) {
            const bounds = ramp.bounds;
            const bottomY = bounds.max.y;
            const diff = currentY - bottomY;
            Matter.Body.setPosition(ramp, { x: ramp.position.x, y: ramp.position.y + diff + 5 }); 

            rampBodies.push(ramp);
            segmentsSinceRamp = 0;
            featurePlaced = true;
        }
    }

    // --- Decorations ---
    // 1. Grass (Earth Only)
    if (mapType === 'earth') {
        const density = 0.4 * slopeFactor; 
        if (Math.random() < density) {
            const t = Math.random();
            const decoX = prevX + (currentX - prevX) * t;
            const decoY = prevY + (currentY - prevY) * t;

            decorations.push({
                x: decoX,
                y: decoY,
                angle: angle,
                scale: 0.5 + Math.random() * 0.5,
                type: Math.floor(Math.random() * 3) 
            });
        }
    }

    // 2. Lamps
    const lampChance = isNight || mapType === 'highway';
    if (lampChance && (currentX - lastLampX) > LAMP_SPACING) {
        decorations.push({
            x: currentX,
            y: currentY,
            angle: angle,
            scale: 1.0,
            type: 3
        });
        lastLampX = currentX;
    }

    // 3. Fences (Highway)
    if (mapType === 'highway') {
        decorations.push({
            x: prevX,
            y: prevY,
            angle: angle,
            scale: 1.0,
            type: 4
        });
    }

    // --- Collectibles (Fuel & Coins) ---
    const forceFuel = segmentsSinceFuel >= 125; 
    const canSpawnFuel = (segmentsSinceFuel > 80 && isFlatEnough) || forceFuel;

    let fuelSpawnedHere = false;

    if (canSpawnFuel) {
        if (forceFuel || Math.random() < 0.1) {
             const cx = prevX + (currentX - prevX) * 0.5;
            const cy = prevY + (currentY - prevY) * 0.5 - 50;

            const fuel = Matter.Bodies.rectangle(cx, cy, FUEL_CAN_SIZE * 0.8, FUEL_CAN_SIZE, {
                isSensor: true,
                isStatic: true,
                label: 'fuel',
                angle: 0,
                render: { visible: false }
            });
            fuelBodies.push(fuel);
            segmentsSinceFuel = 0;
            coinStreak = 0; 
            fuelSpawnedHere = true;
        }
    }

    if (!fuelSpawnedHere && !featurePlaced) {
        let placeCoin = false;
        if (coinStreak > 0) {
            if (isFlatEnough) {
                placeCoin = true;
                coinStreak--;
            } else {
                coinStreak = 0;
            }
        } else {
            if (Math.random() < 0.05 && isFlatEnough) {
                coinStreak = 3 + Math.floor(Math.random() * 6);
                placeCoin = true;
                coinStreak--;
            }
        }

        if (placeCoin) {
            const cx = prevX + (currentX - prevX) * 0.5;
            const cy = prevY + (currentY - prevY) * 0.5 - 50;
            const coin = Matter.Bodies.circle(cx, cy, COIN_SIZE, {
                isSensor: true,
                isStatic: true,
                label: 'coin',
                render: { visible: false }
            });
            coinBodies.push(coin);
        }
    }
  }

  // Create Physics Ground
  const groundParts = [];
  for (let i = 0; i < pathPoints.length - 1; i++) {
     const p1 = pathPoints[i];
     const p2 = pathPoints[i+1];
     const vertices = [
         { x: p1.x, y: p1.y },
         { x: p2.x, y: p2.y },
         { x: p2.x, y: p2.y + groundDepth },
         { x: p1.x, y: p1.y + groundDepth }
     ];
     const center = Matter.Vertices.centre(vertices);
     const body = Matter.Bodies.fromVertices(center.x, center.y, [vertices], {
         isStatic: true,
         friction: config.FRICTION || 1.0, 
         frictionStatic: config.FRICTION || 1.0,
         label: 'ground',
     });
     if (body) groundParts.push(body);
  }

  // Combine all bodies into composite
  const allBodies = [
      ...groundParts, 
      ...coinBodies, 
      ...fuelBodies, 
      ...islandBodies, 
      ...rampBodies, 
      ...obstacleBodies,
      ...boulderBodies,
      ...(finishLineBody ? [finishLineBody] : [])
  ];

  return { 
      composite: Matter.Composite.create({ bodies: allBodies }), 
      pathData: pathPoints,
      decorations,
      coinBodies,
      fuelBodies,
      islandBodies,
      rampBodies,
      obstacleBodies,
      boulderBodies,
      finishLineBody,
      endY: currentY,
      endGlobalIndex: globalIndex,
      nextSegmentsSinceFuel: segmentsSinceFuel, 
      id: chunkId
  };
};

export const generateClouds = (startX: number, length: number): Cloud[] => {
    const clouds: Cloud[] = [];
    const numClouds = Math.floor(length / 400); 

    for (let i = 0; i < numClouds; i++) {
        const x = startX + (Math.random() * length);
        const y = (Math.random() * 500) - 600; 

        clouds.push({
            x,
            y,
            scale: 0.8 + Math.random() * 1.5,
            speedFactor: 0.05 + Math.random() * 0.2, 
            textureId: Math.floor(Math.random() * 3)
        });
    }
    return clouds;
};

export class SoundManager {
    private static audioContext: AudioContext | null = null;
    private static masterGain: GainNode | null = null;
    private static musicGain: GainNode | null = null;
    private static analyser: AnalyserNode | null = null;
    private static dataArray: Uint8Array | null = null;
    private static bufferCache: Map<string, AudioBuffer> = new Map();

    private coinStep: number = 0;
    private lastCoinTime: number = 0;

    // Continuous Sound Nodes
    private engineOsc: OscillatorNode | null = null;
    private engineGain: GainNode | null = null;

    private windSource: AudioBufferSourceNode | null = null;
    private windGain: GainNode | null = null;

    private tireSource: AudioBufferSourceNode | null = null;
    private tireGain: GainNode | null = null;

    // Music Sequencer
    private musicInterval: number | null = null;
    private currentBeat: number = 0;
    private isPlayingMusic: boolean = false;

    private isInitialized: boolean = false;

    constructor() {
      // Lazy init called on first interaction usually, but we set up structure
    }

    private init() {
        if (typeof window === 'undefined') return;

        if (!SoundManager.audioContext) {
            const AudioContextClass = (window.AudioContext || (window as any).webkitAudioContext);
            if (AudioContextClass) {
                const ctx = new AudioContextClass();
                SoundManager.audioContext = ctx;

                // 1. Master Gain
                const masterGain = ctx.createGain();
                masterGain.gain.value = 0.3; 
                SoundManager.masterGain = masterGain;

                // 2. Music Gain (sub-master)
                const musicGain = ctx.createGain();
                musicGain.gain.value = 0.4; // Slightly lower than effects
                musicGain.connect(masterGain);
                SoundManager.musicGain = musicGain;

                // 3. Analyser
                const analyser = ctx.createAnalyser();
                analyser.fftSize = 256; 
                SoundManager.analyser = analyser;
                SoundManager.dataArray = new Uint8Array(analyser.frequencyBinCount);

                masterGain.connect(analyser);
                analyser.connect(ctx.destination);

                // Create Noise Buffers once
                this.createNoiseBuffer('white', ctx);
                this.createNoiseBuffer('brown', ctx);
            }
        }

        if (SoundManager.audioContext && !this.isInitialized) {
            this.setupContinuousSounds();
            this.isInitialized = true;
        }
    }

    private createNoiseBuffer(type: 'white' | 'brown', ctx: AudioContext) {
        if (SoundManager.bufferCache.has(type)) return;

        const bufferSize = ctx.sampleRate * 2; // 2 seconds
        const buffer = ctx.createBuffer(1, bufferSize, ctx.sampleRate);
        const data = buffer.getChannelData(0);

        let lastOut = 0;
        for (let i = 0; i < bufferSize; i++) {
            if (type === 'white') {
                data[i] = Math.random() * 2 - 1;
            } else {
                // Brown noise approximation
                const white = Math.random() * 2 - 1;
                data[i] = (lastOut + (0.02 * white)) / 1.02;
                lastOut = data[i];
                data[i] *= 3.5; // Compensate for gain loss
            }
        }
        SoundManager.bufferCache.set(type, buffer);
    }

    private setupContinuousSounds() {
        const ctx = SoundManager.audioContext;
        const master = SoundManager.masterGain;
        if (!ctx || !master) return;

        // --- ENGINE ---
        this.engineOsc = ctx.createOscillator();
        this.engineOsc.type = 'sawtooth';
        this.engineOsc.frequency.value = 60;

        // Engine Filter (Lowpass to muffle the harsh saw)
        const engineFilter = ctx.createBiquadFilter();
        engineFilter.type = 'lowpass';
        engineFilter.frequency.value = 400;

        this.engineGain = ctx.createGain();
        this.engineGain.gain.value = 0;

        this.engineOsc.connect(engineFilter);
        engineFilter.connect(this.engineGain);
        this.engineGain.connect(master);
        this.engineOsc.start();

        // --- WIND (In Air) ---
        const whiteBuffer = SoundManager.bufferCache.get('white');
        if (whiteBuffer) {
            this.windSource = ctx.createBufferSource();
            this.windSource.buffer = whiteBuffer;
            this.windSource.loop = true;

            const windFilter = ctx.createBiquadFilter();
            windFilter.type = 'bandpass';
            windFilter.frequency.value = 800; // Higher freq for "air" feel

            this.windGain = ctx.createGain();
            this.windGain.gain.value = 0;

            this.windSource.connect(windFilter);
            windFilter.connect(this.windGain);
            this.windGain.connect(master);
            this.windSource.start();
        }

        // --- TIRES (On Ground) ---
        const brownBuffer = SoundManager.bufferCache.get('brown');
        if (brownBuffer) {
            this.tireSource = ctx.createBufferSource();
            this.tireSource.buffer = brownBuffer;
            this.tireSource.loop = true;

            this.tireGain = ctx.createGain();
            this.tireGain.gain.value = 0;

            this.tireSource.connect(this.tireGain);
            this.tireGain.connect(master);
            this.tireSource.start();
        }
    }

    public resume() {
      const ctx = SoundManager.audioContext;
      if (!ctx) {
          this.init();
          return;
      }
      if (ctx.state === 'suspended' || (ctx.state as string) === 'interrupted') {
        ctx.resume();
      }
      if (!this.isInitialized) {
          this.setupContinuousSounds();
          this.isInitialized = true;
      }
      if (!this.isPlayingMusic) {
          this.startMusic();
      }
    }

    // --- MUSIC SEQUENCER ---
    public startMusic() {
        if (this.isPlayingMusic || !SoundManager.audioContext) return;
        this.isPlayingMusic = true;
        const bpm = 90;
        const stepTime = (60 / bpm) * 1000 / 2; // 8th notes

        // Progression: Am - F - C - G
        // Chords: A-C-E, F-A-C, C-E-G, G-B-D
        // Bass: A, F, C, G

        this.musicInterval = window.setInterval(() => {
            this.playSequencerStep();
        }, stepTime);
    }

    public stopMusic() {
        if (this.musicInterval) {
            clearInterval(this.musicInterval);
            this.musicInterval = null;
        }
        this.isPlayingMusic = false;
    }

    public toggleMusic() {
        if (this.isPlayingMusic) this.stopMusic();
        else this.startMusic();
        return this.isPlayingMusic;
    }

    private playSequencerStep() {
        const ctx = SoundManager.audioContext;
        const dest = SoundManager.musicGain;
        if (!ctx || !dest) return;

        const time = ctx.currentTime;
        const beat = this.currentBeat % 32; // 4 bars of 8 steps

        // Determine Chord
        let chordRoot = 220; // A3
        let chordType = 'minor'; 

        if (beat < 8) { chordRoot = 220; chordType = 'minor'; } // Am
        else if (beat < 16) { chordRoot = 174.61; chordType = 'major'; } // F3
        else if (beat < 24) { chordRoot = 261.63; chordType = 'major'; } // C4
        else { chordRoot = 196.00; chordType = 'major'; } // G3

        // BASS - Play on beat 0 and 4 of each bar
        if (beat % 8 === 0 || beat % 8 === 4) {
             this.playNote(chordRoot / 2, time, 0.5, 'triangle', 0.5); // Lower octave
        }

        // PIANO ARPEGGIO - Simple Pattern
        const intervals = chordType === 'minor' ? [0, 3, 7, 12] : [0, 4, 7, 12];
        // Pattern: Root, Third, Fifth, Octave, Fifth, Third, Root, Fifth
        const patternIndices = [0, 1, 2, 3, 2, 1, 0, 2];
        const noteIndex = patternIndices[beat % 8];
        const freq = chordRoot * Math.pow(2, intervals[noteIndex]/12);

        // Slightly randomize velocity
        const velocity = 0.1 + Math.random() * 0.05;
        this.playNote(freq, time, 0.2, 'sine', velocity); // Sine for soft piano

        // STRINGS / PAD - Long chords on start of bar
        if (beat % 8 === 0) {
            // Play triad
            this.playPadNote(chordRoot, time, 2.0);
            this.playPadNote(chordRoot * Math.pow(2, intervals[1]/12), time, 2.0);
            this.playPadNote(chordRoot * Math.pow(2, intervals[2]/12), time, 2.0);
        }

        this.currentBeat++;
    }

    private playNote(freq: number, time: number, duration: number, type: OscillatorType, vol: number) {
        const ctx = SoundManager.audioContext!;
        const dest = SoundManager.musicGain!;

        const osc = ctx.createOscillator();
        const gain = ctx.createGain();

        osc.type = type;
        osc.frequency.setValueAtTime(freq, time);

        gain.gain.setValueAtTime(0, time);
        gain.gain.linearRampToValueAtTime(vol, time + 0.02);
        gain.gain.exponentialRampToValueAtTime(0.01, time + duration);

        osc.connect(gain);
        gain.connect(dest);

        osc.start(time);
        osc.stop(time + duration + 0.1);
    }

    private playPadNote(freq: number, time: number, duration: number) {
        const ctx = SoundManager.audioContext!;
        const dest = SoundManager.musicGain!;

        const osc = ctx.createOscillator();
        const gain = ctx.createGain();
        const filter = ctx.createBiquadFilter();

        osc.type = 'sawtooth';
        osc.frequency.setValueAtTime(freq, time);

        filter.type = 'lowpass';
        filter.frequency.setValueAtTime(400, time);
        filter.frequency.linearRampToValueAtTime(800, time + duration/2);

        gain.gain.setValueAtTime(0, time);
        gain.gain.linearRampToValueAtTime(0.05, time + 0.5); // Slow attack
        gain.gain.linearRampToValueAtTime(0, time + duration); // Slow release

        osc.connect(filter);
        filter.connect(gain);
        gain.connect(dest);

        osc.start(time);
        osc.stop(time + duration);
    }

    public updateContinuous(speedRatio: number, isGrounded: boolean, isGasPressed: boolean) {
        const ctx = SoundManager.audioContext;
        if (!ctx || !this.isInitialized) return;
        const t = ctx.currentTime;

        // Clamp speed ratio 0-1 (approx)
        const speed = Math.max(0, Math.min(1, Math.abs(speedRatio)));

        // --- ENGINE ---
        if (this.engineOsc && this.engineGain) {
            // Pitch: 80Hz idle -> 300Hz max
            const targetFreq = 80 + (speed * 220) + (isGasPressed ? 50 : 0);
            this.engineOsc.frequency.setTargetAtTime(targetFreq, t, 0.1);

            // Volume: Idle 0.1, Moving/Gas 0.3
            const targetGain = 0.1 + (speed * 0.1) + (isGasPressed ? 0.1 : 0);
            this.engineGain.gain.setTargetAtTime(targetGain, t, 0.1);
        }

        // --- TIRES ---
        if (this.tireGain) {
            // Only audible when grounded and moving
            const tireVol = isGrounded && speed > 0.1 ? Math.min(0.2, speed * 0.3) : 0;
            this.tireGain.gain.setTargetAtTime(tireVol, t, 0.1);
        }

        // --- WIND ---
        if (this.windGain) {
            // Reduced volume heavily
            let windVol = speed * 0.05; 
            if (!isGrounded) windVol += 0.05; // Slightly more in air, but much quieter than before
            if (speed < 0.1) windVol = 0;

            this.windGain.gain.setTargetAtTime(windVol, t, 0.2);
        }
    }

    public getAudioLevel(): number {
        if (!SoundManager.analyser || !SoundManager.dataArray) return 0;
        SoundManager.analyser.getByteTimeDomainData(SoundManager.dataArray);

        let sum = 0;
        for (let i = 0; i < SoundManager.dataArray.length; i++) {
            const amplitude = (SoundManager.dataArray[i] - 128) / 128;
            sum += amplitude * amplitude;
        }

        const rms = Math.sqrt(sum / SoundManager.dataArray.length);
        // Adjusted sensitivity
        return Math.min(1.0, rms * 10); 
    }

    public playCoinSound() {
      if (!SoundManager.audioContext) this.init();
      const ctx = SoundManager.audioContext;
      const master = SoundManager.masterGain;
      if (!ctx || !master) return;

      const now = Date.now();
      if (now - this.lastCoinTime > 2000) {
        this.coinStep = 0;
      }
      this.lastCoinTime = now;

      // Shifted scale up another octave (C7)
      const scale = [2093.00, 2349.32, 2637.02, 2793.83, 3135.96, 3520.00, 3951.07, 4186.01]; 
      const frequency = scale[this.coinStep % scale.length];

      const osc = ctx.createOscillator();
      const gain = ctx.createGain();

      osc.type = 'sine'; // Single pure wave
      osc.frequency.setValueAtTime(frequency, ctx.currentTime);

      // Simple envelope
      gain.gain.setValueAtTime(0, ctx.currentTime);
      gain.gain.linearRampToValueAtTime(0.2, ctx.currentTime + 0.02); // Faster attack
      gain.gain.linearRampToValueAtTime(0.01, ctx.currentTime + 0.3);

      osc.connect(gain);
      gain.connect(master);

      osc.start();
      osc.stop(ctx.currentTime + 0.35);

      this.coinStep++;
    }

    public playFlipSound() {
        if (!SoundManager.audioContext) this.init();
        const ctx = SoundManager.audioContext;
        const master = SoundManager.masterGain;
        if (!ctx || !master) return;

        const osc = ctx.createOscillator();
        const gain = ctx.createGain();

        osc.type = 'triangle'; 
        osc.frequency.setValueAtTime(300, ctx.currentTime);
        osc.frequency.exponentialRampToValueAtTime(600, ctx.currentTime + 0.3);

        gain.gain.setValueAtTime(0.15, ctx.currentTime); 
        gain.gain.linearRampToValueAtTime(0.01, ctx.currentTime + 0.3);

        osc.connect(gain);
        gain.connect(master);

        osc.start();
        osc.stop(ctx.currentTime + 0.35);
    }

    public playDoubleFlipSound() {
        if (!SoundManager.audioContext) this.init();
        const ctx = SoundManager.audioContext;
        const master = SoundManager.masterGain;
        if (!ctx || !master) return;

        // Major Third Arpeggio
        const notes = [600, 750, 900];
        const now = ctx.currentTime;

        notes.forEach((freq, i) => {
            const osc = ctx.createOscillator();
            const gain = ctx.createGain();

            osc.type = 'square';
            osc.frequency.value = freq;

            const start = now + (i * 0.1);
            gain.gain.setValueAtTime(0, start);
            gain.gain.linearRampToValueAtTime(0.1, start + 0.05);
            gain.gain.linearRampToValueAtTime(0, start + 0.3);

            osc.connect(gain);
            gain.connect(master);
            osc.start(start);
            osc.stop(start + 0.4);
        });
    }

    public startAirSound() {} 
    public stopAirSound() {}
}

