                  ${isSelected ? 'border-amber-500 bg-neutral-800 shadow-[0_0_30px_rgba(245,158,11,0.1)]' : 'border-neutral-800 bg-neutral-900 hover:border-neutral-600'}
                `}
              >
                {isSelected && (
                  <div className="absolute top-0 right-0 bg-amber-500 text-black text-[10px] font-bold px-3 py-1 rounded-bl-xl rounded-tr-xl tracking-widest uppercase">
                    Equipped
                  </div>
                )}

                <div className="flex flex-col sm:flex-row items-center gap-6 mb-6">
