export class SoundManager {
    private static audioContext: AudioContext | null = null;
    private static masterGain: GainNode | null = null;
    private static musicGain: GainNode | null = null;
    private static analyser: AnalyserNode | null = null;
    private static dataArray: Uint8Array | null = null;
    private static bufferCache: Map<string, AudioBuffer> = new Map();

    // Static Music Sequencer State
    private static musicInterval: number | null = null;
    private static currentBeat: number = 0;
    private static isPlayingMusic: boolean = false;

    private coinStep: number = 0;
    private lastCoinTime: number = 0;

    // Continuous Sound Nodes (Instance based for specific car context)
    private engineOsc: OscillatorNode | null = null;
    private engineGain: GainNode | null = null;

    private windSource: AudioBufferSourceNode | null = null;
    private windGain: GainNode | null = null;

    private tireSource: AudioBufferSourceNode | null = null;
    private tireGain: GainNode | null = null;

    private isInitialized: boolean = false;

    constructor() {
      // Lazy init called on first interaction usually
      if (typeof window !== 'undefined' && !SoundManager.audioContext) {
          SoundManager.init();
      }
      if (SoundManager.audioContext && !this.isInitialized) {
          this.setupContinuousSounds();
          this.isInitialized = true;
      }
    }

    public static init() {
        if (typeof window === 'undefined') return;

        if (!SoundManager.audioContext) {
            const AudioContextClass = (window.AudioContext || (window as any).webkitAudioContext);
            if (AudioContextClass) {
                const ctx = new AudioContextClass();
                SoundManager.audioContext = ctx;

                // 1. Master Gain
                const masterGain = ctx.createGain();
                masterGain.gain.value = 0.3; 
                SoundManager.masterGain = masterGain;

                // 2. Music Gain (sub-master)
                const musicGain = ctx.createGain();
                musicGain.gain.value = 0.4; // Default
                musicGain.connect(masterGain);
                SoundManager.musicGain = musicGain;

                // 3. Analyser
                const analyser = ctx.createAnalyser();
                analyser.fftSize = 256; 
                SoundManager.analyser = analyser;
                SoundManager.dataArray = new Uint8Array(analyser.frequencyBinCount);

                masterGain.connect(analyser);
                analyser.connect(ctx.destination);

                // Create Noise Buffers once
                SoundManager.createNoiseBuffer('white', ctx);
                SoundManager.createNoiseBuffer('brown', ctx);
            }
        }
    }

    private static createNoiseBuffer(type: 'white' | 'brown', ctx: AudioContext) {
        if (SoundManager.bufferCache.has(type)) return;

        const bufferSize = ctx.sampleRate * 2; // 2 seconds
        const buffer = ctx.createBuffer(1, bufferSize, ctx.sampleRate);
        const data = buffer.getChannelData(0);

        let lastOut = 0;
        for (let i = 0; i < bufferSize; i++) {
            if (type === 'white') {
                data[i] = Math.random() * 2 - 1;
            } else {
                // Brown noise approximation
                const white = Math.random() * 2 - 1;
                data[i] = (lastOut + (0.02 * white)) / 1.02;
                lastOut = data[i];
                data[i] *= 3.5; // Compensate for gain loss
            }
        }
        SoundManager.bufferCache.set(type, buffer);
    }

    private setupContinuousSounds() {
        const ctx = SoundManager.audioContext;
        const master = SoundManager.masterGain;
        if (!ctx || !master) return;

        // --- ENGINE ---
        this.engineOsc = ctx.createOscillator();
        this.engineOsc.type = 'sawtooth';
        this.engineOsc.frequency.value = 60;

        // Engine Filter (Lowpass to muffle the harsh saw)
        const engineFilter = ctx.createBiquadFilter();
        engineFilter.type = 'lowpass';
        engineFilter.frequency.value = 400;

        this.engineGain = ctx.createGain();
        this.engineGain.gain.value = 0;

        this.engineOsc.connect(engineFilter);
        engineFilter.connect(this.engineGain);
        this.engineGain.connect(master);
        this.engineOsc.start();

        // --- WIND (In Air) ---
        const whiteBuffer = SoundManager.bufferCache.get('white');
        if (whiteBuffer) {
            this.windSource = ctx.createBufferSource();
            this.windSource.buffer = whiteBuffer;
            this.windSource.loop = true;

            const windFilter = ctx.createBiquadFilter();
            windFilter.type = 'bandpass';
            windFilter.frequency.value = 800; // Higher freq for "air" feel

            this.windGain = ctx.createGain();
            this.windGain.gain.value = 0;

            this.windSource.connect(windFilter);
            windFilter.connect(this.windGain);
            this.windGain.connect(master);
            this.windSource.start();
        }

        // --- TIRES (On Ground) ---
        const brownBuffer = SoundManager.bufferCache.get('brown');
        if (brownBuffer) {
            this.tireSource = ctx.createBufferSource();
            this.tireSource.buffer = brownBuffer;
            this.tireSource.loop = true;

            this.tireGain = ctx.createGain();
            this.tireGain.gain.value = 0;

            this.tireSource.connect(this.tireGain);
            this.tireGain.connect(master);
            this.tireSource.start();
        }
    }

    public resume() {
      const ctx = SoundManager.audioContext;
      if (!ctx) {
          SoundManager.init();
          return;
      }
      if (ctx.state === 'suspended' || (ctx.state as string) === 'interrupted') {
        ctx.resume();
      }
      if (!this.isInitialized) {
          this.setupContinuousSounds();
          this.isInitialized = true;
      }
      // Ensure music is playing if it should be
      if (!SoundManager.isPlayingMusic) {
          SoundManager.startMusic();
      }
    }

    // --- STATIC MUSIC CONTROLS ---

    public static setMusicVolume(volume: number) {
        if (SoundManager.musicGain && SoundManager.audioContext) {
            const t = SoundManager.audioContext.currentTime;
            SoundManager.musicGain.gain.setTargetAtTime(volume, t, 0.5);
        }
    }

    public static startMusic() {
        if (SoundManager.isPlayingMusic || !SoundManager.audioContext) return;
        SoundManager.isPlayingMusic = true;
        const bpm = 90;
        const stepTime = (60 / bpm) * 1000 / 2; // 8th notes

        SoundManager.musicInterval = window.setInterval(() => {
            SoundManager.playSequencerStep();
        }, stepTime);
    }

    public static stopMusic() {
        if (SoundManager.musicInterval) {
            clearInterval(SoundManager.musicInterval);
            SoundManager.musicInterval = null;
        }
        SoundManager.isPlayingMusic = false;
    }

    public toggleMusic() {
        if (SoundManager.isPlayingMusic) SoundManager.stopMusic();
        else SoundManager.startMusic();
        return SoundManager.isPlayingMusic;
    }

    private static playSequencerStep() {
        const ctx = SoundManager.audioContext;
        const dest = SoundManager.musicGain;
        if (!ctx || !dest) return;

        const time = ctx.currentTime;
        const beat = SoundManager.currentBeat % 32; // 4 bars of 8 steps

        // Determine Chord
        let chordRoot = 220; // A3
        let chordType = 'minor'; 

        if (beat < 8) { chordRoot = 220; chordType = 'minor'; } // Am
        else if (beat < 16) { chordRoot = 174.61; chordType = 'major'; } // F3
        else if (beat < 24) { chordRoot = 261.63; chordType = 'major'; } // C4
        else { chordRoot = 196.00; chordType = 'major'; } // G3

        // BASS - Play on beat 0 and 4 of each bar
        if (beat % 8 === 0 || beat % 8 === 4) {
             SoundManager.playNote(chordRoot / 2, time, 0.5, 'triangle', 0.5); // Lower octave
        }

        // PIANO ARPEGGIO - Simple Pattern
        const intervals = chordType === 'minor' ? [0, 3, 7, 12] : [0, 4, 7, 12];
        // Pattern: Root, Third, Fifth, Octave, Fifth, Third, Root, Fifth
        const patternIndices = [0, 1, 2, 3, 2, 1, 0, 2];
        const noteIndex = patternIndices[beat % 8];
        const freq = chordRoot * Math.pow(2, intervals[noteIndex]/12);

        // Slightly randomize velocity
        const velocity = 0.1 + Math.random() * 0.05;
        SoundManager.playNote(freq, time, 0.2, 'sine', velocity); // Sine for soft piano

        // STRINGS / PAD - Long chords on start of bar
        if (beat % 8 === 0) {
            // Play triad
            SoundManager.playPadNote(chordRoot, time, 2.0);
            SoundManager.playPadNote(chordRoot * Math.pow(2, intervals[1]/12), time, 2.0);
            SoundManager.playPadNote(chordRoot * Math.pow(2, intervals[2]/12), time, 2.0);
        }

        SoundManager.currentBeat++;
    }

    private static playNote(freq: number, time: number, duration: number, type: OscillatorType, vol: number) {
        const ctx = SoundManager.audioContext!;
        const dest = SoundManager.musicGain!;

        const osc = ctx.createOscillator();
        const gain = ctx.createGain();

        osc.type = type;
        osc.frequency.setValueAtTime(freq, time);

        gain.gain.setValueAtTime(0, time);
        gain.gain.linearRampToValueAtTime(vol, time + 0.02);
        gain.gain.exponentialRampToValueAtTime(0.01, time + duration);

        osc.connect(gain);
        gain.connect(dest);

        osc.start(time);
        osc.stop(time + duration + 0.1);
    }

    private static playPadNote(freq: number, time: number, duration: number) {
        const ctx = SoundManager.audioContext!;
        const dest = SoundManager.musicGain!;

        const osc = ctx.createOscillator();
        const gain = ctx.createGain();
        const filter = ctx.createBiquadFilter();

        osc.type = 'sawtooth';
        osc.frequency.setValueAtTime(freq, time);

        filter.type = 'lowpass';
        filter.frequency.setValueAtTime(400, time);
        filter.frequency.linearRampToValueAtTime(800, time + duration/2);

        gain.gain.setValueAtTime(0, time);
        gain.gain.linearRampToValueAtTime(0.05, time + 0.5); // Slow attack
        gain.gain.linearRampToValueAtTime(0, time + duration); // Slow release

        osc.connect(filter);
        filter.connect(gain);
        gain.connect(dest);

        osc.start(time);
        osc.stop(time + duration);
    }

    public updateContinuous(speedRatio: number, isGrounded: boolean, isGasPressed: boolean) {
        const ctx = SoundManager.audioContext;
        if (!ctx || !this.isInitialized) return;
        const t = ctx.currentTime;

        // Clamp speed ratio 0-1 (approx)
        const speed = Math.max(0, Math.min(1, Math.abs(speedRatio)));

        // --- ENGINE ---
        if (this.engineOsc && this.engineGain) {
            // Pitch: 80Hz idle -> 300Hz max
            const targetFreq = 80 + (speed * 220) + (isGasPressed ? 50 : 0);
            this.engineOsc.frequency.setTargetAtTime(targetFreq, t, 0.1);

            // Volume: Idle 0.1, Moving/Gas 0.3
            const targetGain = 0.1 + (speed * 0.1) + (isGasPressed ? 0.1 : 0);
            this.engineGain.gain.setTargetAtTime(targetGain, t, 0.1);
        }

        // --- TIRES ---
        if (this.tireGain) {
            // Only audible when grounded and moving
            const tireVol = isGrounded && speed > 0.1 ? Math.min(0.2, speed * 0.3) : 0;
            this.tireGain.gain.setTargetAtTime(tireVol, t, 0.1);
        }

        // --- WIND ---
        if (this.windGain) {
            // Reduced volume heavily
            let windVol = speed * 0.05; 
            if (!isGrounded) windVol += 0.05; // Slightly more in air, but much quieter than before
            if (speed < 0.1) windVol = 0;

            this.windGain.gain.setTargetAtTime(windVol, t, 0.2);
        }
    }

    public stopContinuous() {
        const ctx = SoundManager.audioContext;
        if (!ctx || !this.isInitialized) return;
        const t = ctx.currentTime;

        // Fade out all continuous sounds
        if (this.engineGain) this.engineGain.gain.setTargetAtTime(0, t, 0.1);
        if (this.windGain) this.windGain.gain.setTargetAtTime(0, t, 0.1);
        if (this.tireGain) this.tireGain.gain.setTargetAtTime(0, t, 0.1);

        // Stop oscillators after fade
        setTimeout(() => {
            if (this.engineOsc) { try { this.engineOsc.stop(); } catch(e){} }
            if (this.windSource) { try { this.windSource.stop(); } catch(e){} }
            if (this.tireSource) { try { this.tireSource.stop(); } catch(e){} }
            this.isInitialized = false;
        }, 200);
    }

    public playCoinSound() {
      if (!SoundManager.audioContext) SoundManager.init();
      const ctx = SoundManager.audioContext;
      const master = SoundManager.masterGain;
      if (!ctx || !master) return;

      const now = Date.now();
      if (now - this.lastCoinTime > 2000) {
        this.coinStep = 0;
      }
      this.lastCoinTime = now;

      // Shifted scale up another octave (C7)
      const scale = [2093.00, 2349.32, 2637.02, 2793.83, 3135.96, 3520.00, 3951.07, 4186.01]; 
      const frequency = scale[this.coinStep % scale.length];

      const osc = ctx.createOscillator();
      const gain = ctx.createGain();

      osc.type = 'sine'; // Single pure wave
      osc.frequency.setValueAtTime(frequency, ctx.currentTime);

      // Simple envelope
      gain.gain.setValueAtTime(0, ctx.currentTime);
      gain.gain.linearRampToValueAtTime(0.2, ctx.currentTime + 0.02); // Faster attack
      gain.gain.linearRampToValueAtTime(0.01, ctx.currentTime + 0.3);

      osc.connect(gain);
      gain.connect(master);

      osc.start();
      osc.stop(ctx.currentTime + 0.35);

      this.coinStep++;
    }
}

