  const cloudsLayerRef = useRef<SVGGElement>(null);
  const backgroundLayerRef = useRef<SVGGElement>(null);
  const musicToggleRef = useRef<HTMLButtonElement>(null);

  // Particle System Refs
  const particlesRef = useRef<Particle[]>([]);
  const particleDomRefs = useRef<(SVGCircleElement | null)[]>([]);

  // Dynamic Obstacle Refs
  const obstacleDomRefs = useRef<Map<number, SVGGElement>>(new Map());
  const boulderDomRefs = useRef<Map<number, SVGGElement>>(new Map());

  // Game state
  const gameStateRef = useRef({
    distance: 0,
    coins: 0,
    isGameOver: false,
    keys: { left: false, right: false }
  });

  // Static Data
  const [clouds, setClouds] = useState<Cloud[]>([]);
  const [stars, setStars] = useState<{x: number, y: number, r: number, opacity: number}[]>([]);
  const [collectedCoinIds, setCollectedCoinIds] = useState<Set<number>>(new Set());
  const [collectedFuelIds, setCollectedFuelIds] = useState<Set<number>>(new Set());

  // Generate static stars for Moon
  useEffect(() => {
      if (selectedMap.backgroundType === 'moon') {
          const s = [];
          for(let i=0; i<150; i++) {
              s.push({
                  x: Math.random() * 2000,
                  y: Math.random() * 1000 - 500,
                  r: Math.random() * 2,
                  opacity: Math.random()
              });
          }
          setStars(s);
      } else {
          setStars([]);
      }
  }, [selectedMap]);

  // Helper to generate a chunk
  const addChunk = useCallback((startX: number) => {
      const { endY, globalIndex, segmentsSinceFuel } = lastChunkDataRef.current;
      const length = config.CHUNK_SIZE;
      const chunkId = Math.floor(startX / length);

      const newChunk = generateTerrainChunk(
          chunkId, 
          startX, 
          endY, 
          globalIndex, 
          length, 
          isNightRef.current,
          config,
          selectedMap.backgroundType,
          segmentsSinceFuel,
          mode === 'LEVELS' && levelConfig ? levelConfig.distance : null
      );

      if (engineRef.current) {
        Matter.World.add(engineRef.current.world, newChunk.composite);
      }
      loadedChunksRef.current.push(newChunk.composite);

      if (selectedMap.backgroundType === 'earth' || selectedMap.backgroundType === 'highway') {
          const newClouds = generateClouds(startX, length);
          setClouds(prev => [...prev, ...newClouds]);
      }

      lastChunkDataRef.current = {
          endX: startX + length,
          endY: newChunk.endY,
          globalIndex: newChunk.endGlobalIndex,
          segmentsSinceFuel: newChunk.nextSegmentsSinceFuel
      };

      setChunks(prev => [...prev, newChunk]);
  }, [config, selectedMap.backgroundType, mode, levelConfig]);

  // Apply Config Updates Real-time
  useEffect(() => {
     if (engineRef.current) {
         engineRef.current.gravity.y = config.GRAVITY;
     }
  }, [config.GRAVITY]);

  // Initialize Particles
  useEffect(() => {
      particlesRef.current = Array.from({ length: config.PARTICLE_POOL_SIZE }).map(() => ({
          x: 0, y: 0, vx: 0, vy: 0, life: 0, maxLife: 0, active: false, type: 'dust'
      }));
  }, [config.PARTICLE_POOL_SIZE]);

  // Pause Handlers
  const togglePause = () => {
      if (isMenuBackground) return;
      const nextState = !isPaused;
      setIsPaused(nextState);
      pausedRef.current = nextState;
      if (nextState && soundManagerRef.current) {
          SoundManager.stopMusic();
      } else if (!nextState && soundManagerRef.current) {
          soundManagerRef.current.resume();
      }
  };

  const handleResume = () => {
      setIsPaused(false);
      pausedRef.current = false;
      soundManagerRef.current?.resume();
  };

  const toggleMusic = () => {
      soundManagerRef.current?.toggleMusic();
  };

  // Initialize Game
  useEffect(() => {
    // Only init sound manager if this is the active game, not the background menu visualization
    if (!isMenuBackground) {
        soundManagerRef.current = new SoundManager();
    }

    const engine = createEngine(config);
    engineRef.current = engine;

    const car = createCar(200, -100, selectedCar, config); 
    carRef.current = car;

    const wall = createWall(-1000);
    wallRef.current = wall;

    Matter.World.add(engine.world, [car, wall]);

    lastChunkDataRef.current = { endX: 0, endY: 200, globalIndex: 0, segmentsSinceFuel: 0 }; 
    addChunk(0);
    addChunk(config.CHUNK_SIZE);

    // Collision Events
    Matter.Events.on(engine, 'collisionStart', (event: any) => {
        const pairs = event.pairs;

        for (let i = 0; i < pairs.length; i++) {
            const pair = pairs[i];
            const bodyA = pair.bodyA;
            const bodyB = pair.bodyB;

            // Ground Detection Logic (Wheels)
            const isWheelA = bodyA.label === 'wheelBack' || bodyA.label === 'wheelFront';
            const isWheelB = bodyB.label === 'wheelBack' || bodyB.label === 'wheelFront';
            const isGround = (b: any) => b.label === 'ground' || b.label === 'obstacle'; 

            if ((isWheelA && isGround(bodyB)) || (isWheelB && isGround(bodyA))) {
                wheelGroundContacts.current += 1;
            }

            // Chassis Collision (Game Over check)
            const isChassisA = bodyA.label === 'chassis';
            const isChassisB = bodyB.label === 'chassis';

            // Allow touching obstacles without game over, but ground triggers it
            const isFatalGround = (b: any) => b.label === 'ground';

            if ((isChassisA && isFatalGround(bodyB)) || (isChassisB && isFatalGround(bodyA))) {
                // If in menu background, ignore game over
                if (isMenuBackground) continue;

                const chassisBody = isChassisA ? bodyA : bodyB;
                const contacts = pair.activeContacts;
                if (contacts) {
                    for (const contact of contacts) {
                        const vertex = contact.vertex;
                        const localX = vertex.x - chassisBody.position.x;
                        const localY = vertex.y - chassisBody.position.y;

                        const angle = -chassisBody.angle;
                        const sin = Math.sin(angle);
                        const cos = Math.cos(angle);

                        const rotatedX = localX * cos - localY * sin;
                        const rotatedY = localX * sin + localY * cos;

                        if (rotatedY < -10 && Math.abs(rotatedX) < 40) {
                            gameStateRef.current.isGameOver = true;
                            soundManagerRef.current?.stopContinuous();
                            onGameOver(gameStateRef.current.distance, gameStateRef.current.coins);
                            break;
                        }
                    }
                }
            }

            // Collectibles & Hazards Logic
            let itemBody = null;
            const isCarPart = (b: any) => ['chassis', 'wheelBack', 'wheelFront'].includes(b.label);

            if (isCarPart(bodyA)) {
                if (['coin', 'fuel', 'finishLine'].includes(bodyB.label)) itemBody = bodyB;
            }
            if (isCarPart(bodyB)) {
                if (['coin', 'fuel', 'finishLine'].includes(bodyA.label)) itemBody = bodyA;
            }

            if (itemBody && !isMenuBackground) {
                // FINISH LINE
                if (itemBody.label === 'finishLine') {
                    gameStateRef.current.isGameOver = true;
                    soundManagerRef.current?.stopContinuous();
                    onLevelComplete(gameStateRef.current.coins);
                }
                // COIN / FUEL
                else if (!processedBodyIds.current.has(itemBody.id)) {
                    processedBodyIds.current.add(itemBody.id);
                    Matter.World.remove(engine.world, itemBody, true);

                    if (itemBody.label === 'coin') {
                        soundManagerRef.current?.playCoinSound(); 
                        gameStateRef.current.coins += config.COIN_VALUE;
                        if (hudCoinsRef.current) hudCoinsRef.current.innerText = `$ ${gameStateRef.current.coins}`;
                        setCollectedCoinIds(prev => { const next = new Set(prev); next.add(itemBody.id); return next; });
                    } else if (itemBody.label === 'fuel') {
                        soundManagerRef.current?.playCoinSound(); 
                        fuelRef.current = Math.min(config.MAX_FUEL, fuelRef.current + config.FUEL_CAN_VALUE);
                        setNotification({ text: "FUEL!", subText: `+${Math.round(config.FUEL_CAN_VALUE/config.MAX_FUEL * 100)}%`, id: Date.now() });
                        setTimeout(() => setNotification(null), 1500);
                        setCollectedFuelIds(prev => { const next = new Set(prev); next.add(itemBody.id); return next; });
                    }
                }
            }

            // Particle Logic
            let wheelBody = null;
            if ((isWheelA && isGround(bodyB))) wheelBody = bodyA;
            if ((isWheelB && isGround(bodyA))) wheelBody = bodyB;

            if (wheelBody) {
                const speed = Matter.Vector.magnitude(wheelBody.velocity);
                if (speed > 5) {
                    spawnParticles(wheelBody.position.x, wheelBody.position.y + 15, 3, speed > 10 ? 'spark' : 'dust');
                }
            }
        }
    });

    Matter.Events.on(engine, 'collisionEnd', (event: any) => {
        const pairs = event.pairs;
        for (let i = 0; i < pairs.length; i++) {
            const pair = pairs[i];
            const bodyA = pair.bodyA;
            const bodyB = pair.bodyB;

            const isWheelA = bodyA.label === 'wheelBack' || bodyA.label === 'wheelFront';
            const isWheelB = bodyB.label === 'wheelBack' || bodyB.label === 'wheelFront';
            const isGround = (b: any) => b.label === 'ground' || b.label === 'obstacle';

            if ((isWheelA && isGround(bodyB)) || (isWheelB && isGround(bodyA))) {
                wheelGroundContacts.current = Math.max(0, wheelGroundContacts.current - 1);
            }
        }
    });

    requestRef.current = requestAnimationFrame(animate);

    return () => {
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
      Matter.Engine.clear(engine);
      // Ensure we completely stop continuous sounds when unmounting
      if (soundManagerRef.current) {
          soundManagerRef.current.stopContinuous();
      }
    };
  }, [addChunk, selectedCar, onGameOver, config.CHUNK_SIZE, config.COIN_VALUE, mode, levelConfig, onLevelComplete, isMenuBackground]);

  const spawnParticles = (x: number, y: number, count: number, type: 'dust' | 'spark' | 'explosion') => {
      let spawned = 0;
      for (let i = 0; i < particlesRef.current.length; i++) {
          if (spawned >= count) break;
          const p = particlesRef.current[i];
          if (!p.active) {
              p.active = true;
              p.x = x + (Math.random() * 20 - 10);
              p.y = y + (Math.random() * 20 - 10);
              p.type = type;
              p.maxLife = type === 'explosion' ? 60 : config.PARTICLE_LIFETIME + Math.random() * 20;
              p.life = p.maxLife;

              const speed = type === 'explosion' ? Math.random() * 10 + 5 : Math.random() * 3 + 1;
              const angle = Math.random() * Math.PI * 2;
              p.vx = Math.cos(angle) * speed;
              p.vy = Math.sin(angle) * speed;

              spawned++;
          }
      }
  };

  const interpolateColor = (color1: string, color2: string, factor: number) => {
    const result = /^#?([a-f\d]{2})([a-f\d]{2})([a-f\d]{2})$/i.exec(color1);
    const result2 = /^#?([a-f\d]{2})([a-f\d]{2})([a-f\d]{2})$/i.exec(color2);
    if(result && result2) {
        const r1 = parseInt(result[1], 16), g1 = parseInt(result[2], 16), b1 = parseInt(result[3], 16);
        const r2 = parseInt(result2[1], 16), g2 = parseInt(result2[2], 16), b2 = parseInt(result2[3], 16);
        const r = Math.round(r1 + factor * (r2 - r1));
        const g = Math.round(g1 + factor * (g2 - g1));
        const b = Math.round(b1 + factor * (b2 - b1));
        return `rgb(${r}, ${g}, ${b})`;
    }
    return color1;
  };

  // Ensure Audio Context is resumed on first user interaction
  useEffect(() => {
    const handleInput = () => {
        if (!pausedRef.current) soundManagerRef.current?.resume();
    };
    window.addEventListener('keydown', handleInput);
    window.addEventListener('mousedown', handleInput);
    window.addEventListener('touchstart', handleInput);
    return () => {
        window.removeEventListener('keydown', handleInput);
        window.removeEventListener('mousedown', handleInput);
        window.removeEventListener('touchstart', handleInput);
    };
  }, []);

  useEffect(() => {
    if (isMenuBackground) return; // No input listeners for background

    const handleKeyDown = (e: KeyboardEvent) => {
      if (['ArrowRight', 'd'].includes(e.key)) gameStateRef.current.keys.right = true;
      if (['ArrowLeft', 'a'].includes(e.key)) gameStateRef.current.keys.left = true;
      if (e.key === 'Escape' || e.key === 'p') togglePause();
    };
    const handleKeyUp = (e: KeyboardEvent) => {
      if (['ArrowRight', 'd'].includes(e.key)) gameStateRef.current.keys.right = false;
      if (['ArrowLeft', 'a'].includes(e.key)) gameStateRef.current.keys.left = false;
    };

    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);
    return () => {
      window.removeEventListener('keydown', handleKeyDown);
      window.removeEventListener('keyup', handleKeyUp);
    };
  }, [isPaused, isMenuBackground]); 

  const animate = useCallback(() => {
    const engine = engineRef.current;
    const car = carRef.current;

    if (!engine || !car || gameStateRef.current.isGameOver) return;

    const CONFIG = config;
    const CAR_WHEEL_SIZE = selectedCar.wheelSize || CONFIG.WHEEL_SIZE;
    const CAR_WIDTH = selectedCar.width || CONFIG.CAR_WIDTH;
    const CAR_HEIGHT = selectedCar.height || CONFIG.CAR_HEIGHT;

    // --- DAY/NIGHT CYCLE LOGIC ---
    if (selectedMap.backgroundType === 'earth' || selectedMap.backgroundType === 'highway') {
        gameTimeRef.current = (gameTimeRef.current + 1) % CONFIG.DAY_CYCLE_FRAMES;
        const cycleProgress = gameTimeRef.current / CONFIG.DAY_CYCLE_FRAMES;

        let skyColorStart = selectedMap.skyColorStart;
        let skyColorEnd = selectedMap.skyColorEnd;
        let groundColor = selectedMap.groundColor;

        // Day -> Night (0.4 to 0.5)
        if (cycleProgress > 0.4 && cycleProgress < 0.5) {
            const factor = (cycleProgress - 0.4) * 10; // 0 to 1
            skyColorStart = interpolateColor(selectedMap.skyColorStart, COLORS.skyNightStart, factor);
            skyColorEnd = interpolateColor(selectedMap.skyColorEnd, COLORS.skyNightEnd, factor);
            groundColor = interpolateColor(selectedMap.groundColor, selectedMap.groundDarkColor, factor);
            isNightRef.current = factor > 0.5;
        } 
        // Night -> Day (0.9 to 1.0)
        else if (cycleProgress > 0.9) {
            const factor = (cycleProgress - 0.9) * 10; // 0 to 1
            skyColorStart = interpolateColor(COLORS.skyNightStart, selectedMap.skyColorStart, factor);
            skyColorEnd = interpolateColor(COLORS.skyNightEnd, selectedMap.skyColorEnd, factor);
            groundColor = interpolateColor(selectedMap.groundDarkColor, selectedMap.groundColor, factor);
            isNightRef.current = factor < 0.5;
        } 
        // Night
        else if (cycleProgress >= 0.5 && cycleProgress <= 0.9) {
            skyColorStart = COLORS.skyNightStart;
            skyColorEnd = COLORS.skyNightEnd;
            groundColor = selectedMap.groundDarkColor;
            isNightRef.current = true;
        }

        if (containerRef.current) {
            containerRef.current.style.background = `linear-gradient(to bottom, ${skyColorStart}, ${skyColorEnd})`;
        }
    } else {
        if (containerRef.current) {
             containerRef.current.style.background = `linear-gradient(to bottom, ${selectedMap.skyColorStart}, ${selectedMap.skyColorEnd})`;
        }
    }

    if (!pausedRef.current) {
        Matter.Engine.update(engine, 1000 / 60);

        // --- CAR PHYSICS LOGIC ---
        const { keys } = gameStateRef.current;
        const chassis = car.bodies.find((b: any) => b.label === 'chassis');
        const wheelBack = car.bodies.find((b: any) => b.label === 'wheelBack');
        const wheelFront = car.bodies.find((b: any) => b.label === 'wheelFront');

        // Auto-drive for menu background
        if (isMenuBackground) {
            keys.right = true;
            // Prevent flipping in menu background
             if (chassis.angle < -0.5) Matter.Body.setAngle(chassis, -0.5);
             if (chassis.angle > 0.5) Matter.Body.setAngle(chassis, 0.5);
        }

        const maxSpeed = selectedCar.speed * (isMenuBackground ? 0.6 : 1.0); // Slower in menu
        const acceleration = selectedCar.acceleration;

        const isGrounded = wheelGroundContacts.current > 0;

        // --- FUEL LOGIC ---
        if (keys.right && !isMenuBackground) {
            fuelRef.current -= CONFIG.FUEL_CONSUMPTION;
            if (fuelRef.current <= 0) {
                fuelRef.current = 0;
                gameStateRef.current.isGameOver = true;
                soundManagerRef.current?.stopContinuous();
                setNotification({ text: "OUT OF FUEL!", subText: "Game Over", id: Date.now() });
                setTimeout(() => onGameOver(gameStateRef.current.distance, gameStateRef.current.coins), 1000);
            }
        }

        if (hudFuelBarRef.current) {
            const pct = (fuelRef.current / CONFIG.MAX_FUEL) * 100;
            hudFuelBarRef.current.style.width = `${pct}%`;
            if (pct < 20) hudFuelBarRef.current.style.backgroundColor = '#ef4444';
            else hudFuelBarRef.current.style.backgroundColor = '#fbbf24';
        }

        // --- AUDIO UPDATE ---
        if (soundManagerRef.current && chassis && !isMenuBackground) {
            const speed = Matter.Vector.magnitude(chassis.velocity);
            const speedRatio = Math.min(1.5, speed / 25);
            soundManagerRef.current.updateContinuous(speedRatio, isGrounded, keys.right);
        }

        const rotationSpeed = isGrounded ? CONFIG.GROUND_ROTATION_SPEED : CONFIG.AIR_ROTATION_SPEED;
        const maxRotation = CONFIG.MAX_ROTATION_SPEED;
        const brakeRotationFactor = 0.5;

        // Stunt Logic (Skip for menu)
        if (isGrounded && !isMenuBackground) {
            if (stuntRef.current.inAir) {
                if (stuntRef.current.airTime > 60) {
                    const seconds = (stuntRef.current.airTime / 60).toFixed(1);
                    const airBonus = Math.floor(stuntRef.current.airTime * 50);
                    const flips = stuntRef.current.flips;
                    let totalBonus = airBonus;
                    let text = `AIR TIME ${seconds}s`;
                    let subText = `+$${airBonus}`;
                    if (flips > 0) {
                        const flipBonus = flips * 1000;
                        totalBonus += flipBonus;
                        text = `${flips > 1 ? 'DOUBLE ' : ''}FLIP!`;
                        subText = `+$${totalBonus} (Air: ${seconds}s)`;
                    }
                    gameStateRef.current.coins += totalBonus;
                    if (hudCoinsRef.current) hudCoinsRef.current.innerText = `${gameStateRef.current.coins}`;
                    setNotification({ text, subText, id: Date.now() });
                    setTimeout(() => setNotification(null), 3000);
                } else if (stuntRef.current.flips > 0) {
                    const bonus = stuntRef.current.flips * 1000;
                    gameStateRef.current.coins += bonus;
                    if (hudCoinsRef.current) hudCoinsRef.current.innerText = `${gameStateRef.current.coins}`;
                    setNotification({ text: `${stuntRef.current.flips > 1 ? 'DOUBLE ' : ''}FLIP!`, subText: `+$${bonus}`, id: Date.now() });
                    setTimeout(() => setNotification(null), 2500);
                }
                stuntRef.current = { inAir: false, startAngle: 0, flips: 0, airTime: 0 };
            }
        } else if (!isMenuBackground) {
            if (!stuntRef.current.inAir) {
                stuntRef.current.inAir = true;
                stuntRef.current.startAngle = chassis.angle;
                stuntRef.current.flips = 0;
                stuntRef.current.airTime = 0;
            } else {
                stuntRef.current.airTime++;
                const diff = Math.abs(chassis.angle - stuntRef.current.startAngle);
                const currentFlips = Math.floor(diff / (Math.PI * 1.8));
                if (currentFlips > stuntRef.current.flips) {
                    stuntRef.current.flips = currentFlips;
                }
            }
        }

        const applyPower = (targetSpeed: number) => {
            if (selectedCar.driveTrain === 'RWD' || selectedCar.driveTrain === 'AWD') {
                Matter.Body.setAngularVelocity(wheelBack, targetSpeed);
            }
            if (selectedCar.driveTrain === 'FWD' || selectedCar.driveTrain === 'AWD') {
                Matter.Body.setAngularVelocity(wheelFront, targetSpeed);
            }
        };

        if (keys.right) {
            const currentSpeed = (selectedCar.driveTrain === 'FWD') ? wheelFront.angularVelocity : wheelBack.angularVelocity;
            if (currentSpeed < maxSpeed) {
                applyPower(Math.min(currentSpeed + acceleration, maxSpeed));
            }
            if (chassis.angularVelocity > -maxRotation) {
                Matter.Body.setAngularVelocity(chassis, chassis.angularVelocity - rotationSpeed);
            }
        } else if (keys.left) {
            const targetReverse = -maxSpeed * 0.5;
            const currentSpeed = (selectedCar.driveTrain === 'FWD') ? wheelFront.angularVelocity : wheelBack.angularVelocity;
            if (currentSpeed > targetReverse) {
                applyPower(Math.max(currentSpeed - acceleration * 1.5, targetReverse));
            }
            if (chassis.angularVelocity < maxRotation) {
                Matter.Body.setAngularVelocity(chassis, chassis.angularVelocity + (rotationSpeed * brakeRotationFactor));
            }
        }

        // Particles Update
        particlesRef.current.forEach((p, i) => {
            const el = particleDomRefs.current[i];
            if (!el) return;

            if (p.active) {
                p.x += p.vx;
                p.y += p.vy;
                p.vy += p.type === 'explosion' ? 0.05 : 0.2; 
                p.life--;

                if (p.life <= 0) {
                    p.active = false;
                    el.setAttribute('visibility', 'hidden');
                } else {
                    el.setAttribute('visibility', 'visible');
                    el.setAttribute('cx', p.x.toString());
                    el.setAttribute('cy', p.y.toString());
                    const color = p.type === 'explosion' ? '#ef4444' : (p.type === 'spark' ? COLORS.particleSpark : selectedMap.particleColor);
                    el.setAttribute('fill', color);
                    el.setAttribute('opacity', (p.life / p.maxLife).toString());
                    el.setAttribute('r', (p.type === 'spark' ? 2 : (p.type === 'explosion' ? 6 : 4)).toString());
                }
            } else {
                el.setAttribute('visibility', 'hidden');
            }
        });

        // Camera Update
        if (svgRef.current) {
            cameraPosRef.current = { x: chassis.position.x, y: chassis.position.y };
            const velocity = Matter.Vector.magnitude(chassis.velocity);
            const speedRatio = Math.min(Math.max(0, velocity - 5) / 20, 1.0);
            const targetZoom = 1.0 + speedRatio * (CONFIG.MAX_ZOOM_FACTOR - 1.0);
            cameraZoomRef.current = cameraZoomRef.current + (targetZoom - cameraZoomRef.current) * 0.05;

            const currentZoom = cameraZoomRef.current;
            const viewW = CONFIG.BASE_VIEWPORT_WIDTH * currentZoom;
            const viewH = CONFIG.BASE_VIEWPORT_HEIGHT * currentZoom;

            const viewBoxX = chassis.position.x - viewW * 0.3; 
            const viewBoxY = chassis.position.y - viewH * 0.6; 

            svgRef.current.setAttribute('viewBox', `${viewBoxX} ${viewBoxY} ${viewW} ${viewH}`);

            if (backgroundLayerRef.current) {
                backgroundLayerRef.current.setAttribute('transform', `translate(${chassis.position.x - viewBoxX - (chassis.position.x * 0.02)}, ${chassis.position.y - viewBoxY - 200})`);
            }
        }

        // HUD Update
        const currentDist = Math.max(0, Math.floor((chassis.position.x - 200) / 10)); 
        gameStateRef.current.distance = currentDist;
        if (hudDistanceRef.current) hudDistanceRef.current.innerText = `${currentDist}`;

        // Chunk Loading
        if (chassis.position.x > lastChunkDataRef.current.endX - CONFIG.RENDER_DISTANCE) {
            addChunk(lastChunkDataRef.current.endX);
        }

        // Wall Update
        const wallTargetX = chassis.position.x - CONFIG.WALL_DISTANCE;
        if (wallRef.current && wallTargetX > wallRef.current.position.x) {
            Matter.Body.setPosition(wallRef.current, { x: wallTargetX, y: chassis.position.y });
        }
    }

    // --- RENDER (Visuals only, no physics updates) ---
    const chassis = car.bodies.find((b: any) => b.label === 'chassis');
    const wheelBack = car.bodies.find((b: any) => b.label === 'wheelBack');
    const wheelFront = car.bodies.find((b: any) => b.label === 'wheelFront');

    if (chassisDomRef.current) {
        const cPos = chassis.position;
        const cAngle = chassis.angle * (180 / Math.PI);
        chassisDomRef.current.setAttribute('transform', `translate(${cPos.x}, ${cPos.y}) rotate(${cAngle})`);
    }

    if (wheelBackDomRef.current) {
        const wbPos = wheelBack.position;
        const wbAngle = wheelBack.angle * (180 / Math.PI);
        wheelBackDomRef.current.setAttribute('transform', `translate(${wbPos.x}, ${wbPos.y}) rotate(${wbAngle})`);
    }

    if (wheelFrontDomRef.current) {
        const wfPos = wheelFront.position;
        const wfAngle = wheelFront.angle * (180 / Math.PI);
        wheelFrontDomRef.current.setAttribute('transform', `translate(${wfPos.x}, ${wfPos.y}) rotate(${wfAngle})`);
    }

    // --- RENDER DYNAMIC OBSTACLES ---
    chunks.forEach(chunk => {
        // Boxes
        if (chunk.obstacleBodies) {
            chunk.obstacleBodies.forEach(body => {
                const el = obstacleDomRefs.current.get(body.id);
                if (el) {
                    const pos = body.position;
                    const angle = body.angle * (180 / Math.PI);
                    el.setAttribute('transform', `translate(${pos.x}, ${pos.y}) rotate(${angle})`);
                }
            });
        }
        // Boulders
        if (chunk.boulderBodies) {
             chunk.boulderBodies.forEach(body => {
                const el = boulderDomRefs.current.get(body.id);
                if (el) {
                    const pos = body.position;
                    const angle = body.angle * (180 / Math.PI);
                    el.setAttribute('transform', `translate(${pos.x}, ${pos.y}) rotate(${angle})`);
                }
             });
        }
    });

    requestRef.current = requestAnimationFrame(animate);
  }, [onGameOver, addChunk, selectedCar, config, selectedMap, isMenuBackground]);

  const decorationsElements = useMemo(() => {
    return chunks.flatMap(chunk => 
        chunk.decorations.map((deco, i) => {
           const angleDeg = deco.angle * (180/Math.PI);
           if (deco.type === 5) {
               // Finish Line
               return (
                   <g key={`finish-${chunk.id}-${i}`} transform={`translate(${deco.x}, ${deco.y})`}>
                       {/* Left Pole */}
                       <rect x="-100" y="-300" width="10" height="300" fill={COLORS.finishLinePole} />
                       {/* Right Pole */}
                       <rect x="100" y="-300" width="10" height="300" fill={COLORS.finishLinePole} />
                       {/* Banner */}
                       <rect x="-100" y="-280" width="210" height="60" fill={COLORS.finishLineCheckered} />
                       <text x="5" y="-240" textAnchor="middle" fontSize="40" fontWeight="bold" fill="black">FINISH</text>

                       {/* Checkered Pattern */}
                       <path d="M -100 -280 h 20 v 20 h -20 z M -60 -280 h 20 v 20 h -20 z" fill="black" opacity="0.2" />
                   </g>
               )
           }
           if (deco.type === 4) {
             return (
               <g key={`fence-${chunk.id}-${i}`} transform={`translate(${deco.x}, ${deco.y}) rotate(${angleDeg})`}>
                  <rect x="-2" y="-15" width="4" height="15" fill="#64748b" />
                  <rect x="-20" y="-12" width="45" height="4" fill="#94a3b8" />
                  <rect x="-20" y="-8" width="45" height="1" fill="#cbd5e1" opacity="0.5" />
               </g>
             );
           }
           if (deco.type === 3) {
             return (
               <g key={`lamp-${chunk.id}-${i}`} transform={`translate(${deco.x}, ${deco.y}) rotate(${angleDeg})`}>
                  <rect x="-2" y="-80" width="4" height="80" fill={COLORS.lampPost} />
                  <rect x="0" y="-85" width="25" height="5" fill={COLORS.lampPost} />
                  <circle cx="20" cy="-80" r="5" fill={COLORS.lampLight} />
                  <circle cx="20" cy="-80" r="40" fill="url(#lampGlowGradient)" />
               </g>
             )
           }
           if (selectedMap.backgroundType === 'moon') {
               return (
                 <g key={`rock-${chunk.id}-${i}`} transform={`translate(${deco.x}, ${deco.y}) rotate(${angleDeg})`}>
                     <circle cx="0" cy="5" r={deco.scale * 5} fill={selectedMap.groundDarkColor} opacity="0.6" />
                 </g>
               )
           }
           if (selectedMap.backgroundType === 'highway') {
               return null; 
           }
           const d = `M 0 0 Q 5 -15 0 -25 Q -5 -15 0 0 M -3 0 Q -8 -10 -5 -20 M 3 0 Q 8 -10 5 -20`;
           return (
             <g key={`grass-${chunk.id}-${i}`} transform={`translate(${deco.x}, ${deco.y}) rotate(${angleDeg + 90}) scale(${deco.scale})`}>
                <path d={d} stroke={COLORS.grassDetail} strokeWidth="2" fill="none" opacity="0.8" />
             </g>
           );
        })
    );
  }, [chunks, selectedMap]);

  const terrainPaths = useMemo(() => {
      return chunks.map(chunk => {
        const points = chunk.pathData;
        if (points.length === 0) return null;
        let path = `M ${points[0].x} ${points[0].y}`;
        for(let i=1; i<points.length; i++) {
            path += ` L ${points[i].x} ${points[i].y}`;
        }
        path += ` L ${points[points.length-1].x} ${points[points.length-1].y + 800}`;
        path += ` L ${points[0].x} ${points[0].y + 800}`;
        path += " Z"; 
        return (
            <path 
                key={`terrain-${chunk.id}`}
                d={path} 
                fill="url(#groundPattern)" 
                stroke={selectedMap.groundDarkColor} 
                strokeWidth="5" 
                strokeLinejoin="round"
            />
        );
      });
  }, [chunks, selectedMap]);

  const obstacleElements = useMemo(() => {
      return chunks.flatMap(chunk => 
        (chunk.obstacleBodies || []).map(body => {
            const size = (body.bounds.max.x - body.bounds.min.x);
            return (
                <g 
                    key={`obstacle-${body.id}`} 
                    ref={(el) => { if(el) obstacleDomRefs.current.set(body.id, el); }}
                    transform={`translate(${body.position.x}, ${body.position.y})`}
                >
                    <rect x={-size/2} y={-size/2} width={size} height={size} fill={COLORS.obstacleBox} stroke={COLORS.obstacleBoxBorder} strokeWidth="3" rx="4" />
                    <path d={`M -${size/4} -${size/4} L ${size/4} ${size/4} M ${size/4} -${size/4} L -${size/4} ${size/4}`} stroke={COLORS.obstacleBoxBorder} strokeWidth="2" opacity="0.6" />
                </g>
            )
        })
      )
  }, [chunks]);

  const boulderElements = useMemo(() => {
    return chunks.flatMap(chunk => 
      (chunk.boulderBodies || []).map(body => {
          const radius = (body.bounds.max.x - body.bounds.min.x) / 2;
          return (
              <g 
                  key={`boulder-${body.id}`} 
                  ref={(el) => { if(el) boulderDomRefs.current.set(body.id, el); }}
                  transform={`translate(${body.position.x}, ${body.position.y})`} 
              >
                  <circle r={radius} fill={COLORS.boulder} stroke={COLORS.boulderDark} strokeWidth="3" />
                  <path d={`M -${radius*0.5} -${radius*0.2} L ${radius*0.3} ${radius*0.4}`} stroke={COLORS.boulderDark} strokeWidth="2" />
                  <circle cx={radius*0.4} cy={-radius*0.3} r={radius*0.15} fill={COLORS.boulderDark} opacity="0.5" />
              </g>
          )
      })
    )
  }, [chunks]);

  const hazardElements = useMemo(() => {
      return chunks.flatMap(chunk => {
          const elements = [];

          // ISLANDS & RAMPS
          const groundBodies = [
              ...(chunk.islandBodies || []), 
              ...(chunk.rampBodies || [])
          ];

          if (groundBodies.length > 0) {
              groundBodies.forEach(b => {
                  if (b.vertices && b.vertices.length > 0) {
                      let path = `M ${b.vertices[0].x} ${b.vertices[0].y}`;
                      for (let i = 1; i < b.vertices.length; i++) {
                          path += ` L ${b.vertices[i].x} ${b.vertices[i].y}`;
                      }
                      path += ' Z';

                      elements.push(
                          <g key={`ground-body-${b.id}`}>
                              {/* Main body using ground pattern */}
                              <path 
                                d={path} 
                                fill="url(#groundPattern)" 
                                stroke={selectedMap.groundColor} 
                                strokeWidth="2" 
                              />
                          </g>
                      );
                  }
              });
          }
          return elements;
      });
  }, [chunks, selectedMap]);

  const coinElements = useMemo(() => {
      return chunks.flatMap(chunk => 
          chunk.coinBodies.map((coinBody) => {
              if (collectedCoinIds.has(coinBody.id)) return null;
              return (
                  <g key={`coin-${coinBody.id}`} transform={`translate(${coinBody.position.x}, ${coinBody.position.y})`}>
                      <circle r={config.COIN_SIZE} fill={COLORS.coinOuter} />
                      <circle r={config.COIN_SIZE * 0.7} fill={COLORS.coinInner} />
                      <text y="5" textAnchor="middle" fontSize="14" fontWeight="bold" fill="#B45309">$</text>
                      <circle cx="-4" cy="-4" r="3" fill="white" opacity="0.5" />
                  </g>
              );
          })
      );
  }, [chunks, collectedCoinIds, config.COIN_SIZE]);

  const fuelElements = useMemo(() => {
    return chunks.flatMap(chunk => 
        chunk.fuelBodies.map((fuelBody) => {
            if (collectedFuelIds.has(fuelBody.id)) return null;
            return (
                <g key={`fuel-${fuelBody.id}`} transform={`translate(${fuelBody.position.x}, ${fuelBody.position.y})`}>
                    <rect x="-8" y="-12" width="16" height="24" rx="2" fill={COLORS.fuelCan} />
                    <rect x="-8" y="-12" width="16" height="5" fill="#b91c1c" />
                    <rect x="0" y="-15" width="6" height="4" fill={COLORS.fuelCanCap} />
                    <path d="M -8 -8 Q -12 -12 -8 -16" stroke={COLORS.fuelCan} strokeWidth="3" fill="none" />
                    <text y="5" x="0" textAnchor="middle" fontSize="8" fontWeight="bold" fill="white">FUEL</text>
                </g>
            );
        })
    );
}, [chunks, collectedFuelIds]);

  const cloudElements = useMemo(() => {
      return clouds.map((cloud, i) => (
          <g key={`cloud-${i}`} transform={`translate(${cloud.x}, ${cloud.y}) scale(${cloud.scale})`}>
              <path 
                d="M 25,60 Q 40,30 70,50 Q 90,20 120,50 Q 150,30 170,60 Q 190,60 190,80 Q 190,110 160,110 L 40,110 Q 10,110 10,80 Q 10,60 25,60 Z" 
                fill="white" 
                opacity="0.6"
              />
          </g>
      ));
  }, [clouds]);

  const backgroundElements = useMemo(() => {
      if (selectedMap.backgroundType === 'moon') {
          return (
              <g ref={backgroundLayerRef}>
                  {stars.map((s, i) => (
                      <circle key={i} cx={s.x} cy={s.y} r={s.r} fill="white" opacity={s.opacity} />
                  ))}
                  <circle cx="800" cy="-200" r="100" fill="#2563eb" opacity="0.8" />
                  <circle cx="820" cy="-250" r="30" fill="#16a34a" opacity="0.6" /> 
              </g>
          )
      }
      return <g ref={backgroundLayerRef}></g>; 
  }, [selectedMap, stars]);

  const gameClass = `relative w-full h-full bg-slate-900 overflow-hidden cursor-none select-none transition-colors duration-1000 font-sans ${isMenuBackground ? 'grayscale opacity-60' : ''}`;

  return (
    <div ref={containerRef} className={gameClass}>

      {/* Top Bar (Pause, Debug, Music) */}
      {!isMenuBackground && (
      <div className="absolute top-4 right-4 z-30 flex gap-2">
         <button 
            onClick={toggleMusic}
            className="w-10 h-10 bg-black/40 backdrop-blur text-white rounded-full border border-white/20 flex items-center justify-center hover:bg-white/20 transition"
          >
             🎵
          </button>
          <button 
            onClick={togglePause}
            className="w-10 h-10 bg-black/40 backdrop-blur text-white rounded-full border border-white/20 flex items-center justify-center hover:bg-white/20 transition"
          >
             ⏸️
          </button>
          <button 
            onClick={() => setIsDebugOpen(!isDebugOpen)}
            className="w-10 h-10 bg-black/40 backdrop-blur text-white rounded-full border border-white/20 flex items-center justify-center hover:bg-white/20 transition"
          >
             ⚙️
          </button>
      </div>
      )}

      {/* Pause Menu Overlay */}
      {isPaused && (
          <div className="absolute inset-0 z-40 bg-black/60 backdrop-blur-sm flex flex-col items-center justify-center animate-fade-in">
             <div className="bg-neutral-900 border border-neutral-700 p-8 rounded-2xl shadow-2xl flex flex-col gap-4 min-w-[300px]">
                 <h2 className="text-3xl font-black text-center text-white italic tracking-wider mb-2">PAUSED</h2>
                 <button onClick={handleResume} className="py-3 px-6 bg-amber-600 hover:bg-amber-500 rounded-xl font-bold text-white shadow-lg transition">RESUME</button>
                 <button onClick={onExit} className="py-3 px-6 bg-neutral-700 hover:bg-neutral-600 rounded-xl font-bold text-white shadow-lg transition">MAIN MENU</button>
             </div>
          </div>
      )}

      {/* HUD Layer - Refined "Classy" Look */}
      {!isMenuBackground && (
      <div className="absolute top-6 left-6 z-10 pointer-events-none flex flex-col gap-3">
         {/* Top Info Row */}
         <div className="flex items-center gap-4">
            {/* Distance Gauge */}
            <div className="bg-black/60 backdrop-blur-md px-5 py-3 rounded-xl border border-white/10 shadow-lg min-w-[120px]">
                <div className="text-[10px] text-neutral-400 uppercase tracking-widest font-bold mb-1">Distance</div>
                <div className="flex items-baseline gap-1">
                    <span ref={hudDistanceRef} className="text-3xl font-mono font-bold text-white tracking-tighter">0</span>
                    <span className="text-sm text-neutral-500 font-bold">M</span>
                </div>
            </div>

            {/* Level Target (if applicable) */}
            {mode === 'LEVELS' && levelConfig && (
                <div className="bg-black/60 backdrop-blur-md px-5 py-3 rounded-xl border border-blue-500/30 shadow-lg min-w-[120px]">
                    <div className="text-[10px] text-blue-400 uppercase tracking-widest font-bold mb-1">Target</div>
                     <div className="flex items-baseline gap-1">
                        <span className="text-3xl font-mono font-bold text-blue-100 tracking-tighter">{levelConfig.distance}</span>
                        <span className="text-sm text-blue-500 font-bold">M</span>
                    </div>
                </div>
            )}

            {/* Coins */}
             <div className="bg-black/60 backdrop-blur-md px-5 py-3 rounded-xl border border-amber-500/30 shadow-lg flex items-center gap-3">
                 <div className="w-8 h-8 rounded-full bg-amber-500 flex items-center justify-center text-black font-bold border-2 border-amber-300">$</div>
                 <div>
                    <div className="text-[10px] text-amber-500 uppercase tracking-widest font-bold">Credits</div>
                    <div ref={hudCoinsRef} className="text-2xl font-mono font-bold text-white tracking-tighter">0</div>
                 </div>
            </div>
        </div>

        {/* Fuel Gauge - Clean Line */}
        <div className="w-64">
             <div className="flex justify-between items-end mb-1 px-1">
                <span className="text-[10px] text-white/50 uppercase font-bold tracking-widest">Fuel Level</span>
             </div>
             <div className="w-full h-2 bg-neutral-800 rounded-full overflow-hidden border border-white/5">
                <div 
                    ref={hudFuelBarRef}
                    className="h-full bg-gradient-to-r from-red-500 to-amber-500 transition-all duration-200"
                    style={{ width: '100%' }}
                />
             </div>
        </div>
      </div>
      )}

      {/* Floating Notification */}
      {notification && (
          <div className="absolute top-32 left-1/2 transform -translate-x-1/2 z-40 animate-bounce flex flex-col items-center">
              <div className="text-5xl font-black italic text-transparent bg-clip-text bg-gradient-to-b from-white to-neutral-400 drop-shadow-xl whitespace-nowrap">
                  {notification.text}
              </div>
              {notification.subText && (
                  <div className="text-xl font-bold text-amber-400 drop-shadow-md mt-1 tracking-widest uppercase">
                      {notification.subText}
                  </div>
              )}
          </div>
      )}

      {isDebugOpen && (
          <DebugMenu 
             config={config} 
             onUpdate={onUpdateConfig} 
             onClose={() => setIsDebugOpen(false)} 
             onReset={onResetConfig}
          />
      )}

      {/* Controls */}
      {!isMenuBackground && (
      <>
      <div className="absolute bottom-10 left-10 z-30 flex items-center justify-center">
         <button
           className="w-24 h-24 rounded-full border-2 border-white/10 bg-black/40 backdrop-blur-sm active:bg-white/10 active:border-red-500/50 transition-all transform active:scale-95 flex items-center justify-center group"
           onMouseDown={() => { gameStateRef.current.keys.left = true; soundManagerRef.current?.resume(); }}
           onMouseUp={() => gameStateRef.current.keys.left = false}
           onMouseLeave={() => gameStateRef.current.keys.left = false}
           onTouchStart={(e) => { e.preventDefault(); gameStateRef.current.keys.left = true; soundManagerRef.current?.resume(); }}
           onTouchEnd={(e) => { e.preventDefault(); gameStateRef.current.keys.left = false; }}
         >
            <div className="flex flex-col items-center opacity-70 group-hover:opacity-100">
               <span className="text-3xl text-red-400 mb-1">◀</span>
               <span className="text-[10px] font-bold text-red-400 uppercase tracking-widest">Brake</span>
            </div>
         </button>
      </div>

      <div className="absolute bottom-10 right-10 z-30 flex items-center justify-center">
         <button
           className="w-24 h-24 rounded-full border-2 border-white/10 bg-black/40 backdrop-blur-sm active:bg-white/10 active:border-emerald-500/50 transition-all transform active:scale-95 flex items-center justify-center group"
           onMouseDown={() => { gameStateRef.current.keys.right = true; soundManagerRef.current?.resume(); }}
           onMouseUp={() => gameStateRef.current.keys.right = false}
           onMouseLeave={() => gameStateRef.current.keys.right = false}
           onTouchStart={(e) => { e.preventDefault(); gameStateRef.current.keys.right = true; soundManagerRef.current?.resume(); }}
           onTouchEnd={(e) => { e.preventDefault(); gameStateRef.current.keys.right = false; }}
         >
            <div className="flex flex-col items-center opacity-70 group-hover:opacity-100">
               <span className="text-3xl text-emerald-400 mb-1">▶</span>
               <span className="text-[10px] font-bold text-emerald-400 uppercase tracking-widest">Gas</span>
            </div>
         </button>
      </div>
      </>
      )}

      {/* Game World */}
      <svg 
        ref={svgRef}
        className="w-full h-full"
        preserveAspectRatio="xMidYMid slice"
        xmlns="http://www.w3.org/2000/svg"
      >
        <defs>
            <pattern id="groundPattern" patternUnits="userSpaceOnUse" width="40" height="40" patternTransform="rotate(45)">
                <rect width="100%" height="100%" fill={selectedMap.groundColor} />
                <circle cx="10" cy="10" r="2" fill={selectedMap.groundDarkColor} opacity="0.3" />
                <circle cx="30" cy="30" r="3" fill={selectedMap.groundDarkColor} opacity="0.2" />
                <circle cx="15" cy="35" r="1.5" fill={selectedMap.groundDarkColor} opacity="0.4" />
                <circle cx="35" cy="5" r="2" fill={selectedMap.groundDarkColor} opacity="0.2" />
            </pattern>
            <radialGradient id="lampGlowGradient">
                <stop offset="0%" stopColor={COLORS.lampLight} stopOpacity="0.8" />
                <stop offset="50%" stopColor={COLORS.lampGlow} stopOpacity="0.3" />
                <stop offset="100%" stopColor={COLORS.lampGlow} stopOpacity="0" />
            </radialGradient>

            {/* Dynamic Car Pattern */}
            {selectedCar.texture === 'striped' && (
              <pattern id="carBodyPattern" patternUnits="userSpaceOnUse" width="20" height="20" patternTransform="rotate(45)">
                <rect width="20" height="20" fill={selectedCar.bodyColor} />
                <rect width="10" height="20" fill={selectedCar.textureColor2 || selectedCar.bodyColor} />
              </pattern>
            )}
             {selectedCar.texture === 'dots' && (
              <pattern id="carBodyPattern" patternUnits="userSpaceOnUse" width="10" height="10">
                <rect width="10" height="10" fill={selectedCar.bodyColor} />
                <circle cx="5" cy="5" r="2" fill={selectedCar.textureColor2 || 'white'} />
              </pattern>
            )}
             {selectedCar.texture === 'checker' && (
              <pattern id="carBodyPattern" patternUnits="userSpaceOnUse" width="20" height="20">
                <rect width="20" height="20" fill={selectedCar.bodyColor} />
                <rect x="0" y="0" width="10" height="10" fill={selectedCar.textureColor2 || 'black'} />
                <rect x="10" y="10" width="10" height="10" fill={selectedCar.textureColor2 || 'black'} />
              </pattern>
            )}
             {selectedCar.texture === 'gradient' && (
              <linearGradient id="carBodyPattern" x1="0" y1="0" x2="0" y2="1">
                <stop offset="0%" stopColor={selectedCar.textureColor2 || selectedCar.bodyColor} />
                <stop offset="100%" stopColor={selectedCar.bodyColor} />
              </linearGradient>
            )}
        </defs>

        {backgroundElements}

        <g ref={cloudsLayerRef}>
            {cloudElements}
        </g>

        <g>
            {/* Render Islands & Terrain Features First */}
            {hazardElements.filter(e => e.key && (e.key.toString().startsWith('ground-body')))}

            {terrainPaths}

            {decorationsElements}
            {obstacleElements}
            {boulderElements}
            {coinElements}
            {fuelElements}
        </g>

        <g>
            {Array.from({ length: config.PARTICLE_POOL_SIZE }).map((_, i) => (
                <circle 
                    key={`p-${i}`} 
                    ref={el => { particleDomRefs.current[i] = el; }} 
                    r="0" 
                    visibility="hidden" 
                />
            ))}
        </g>

        {/* Car Chassis Group */}
        <g ref={chassisDomRef}>
            {selectedCar.imageUrl ? (
                // Custom Image Rendering
                <image 
                    href={selectedCar.imageUrl} 
                    x={-config.CAR_WIDTH/2 * (selectedCar.imageScale || 1)} 
                    y={-config.CAR_HEIGHT/2 + (selectedCar.imageYOffset || 0) - (config.CAR_HEIGHT/2 * ((selectedCar.imageScale || 1) - 1))} 
                    width={config.CAR_WIDTH * (selectedCar.imageScale || 1)} 
                    height={config.CAR_HEIGHT * (selectedCar.imageScale || 1)} 
                    preserveAspectRatio="xMidYMid meet"
                />
            ) : (
                // Default Vector Rendering based on Shape
                <g>
                    {/* Render Shapes */}
                    {(selectedCar.shape === 'coupe' || !selectedCar.shape) && (
                        <>
                            <path
                                d="M -85 15 L -85 -5 L -75 -15 L -50 -35 L 10 -35 L 40 -15 L 75 -5 L 85 15 Z"
                                fill={selectedCar.texture && selectedCar.texture !== 'plain' ? "url(#carBodyPattern)" : selectedCar.bodyColor}
                                stroke="rgba(0,0,0,0.5)" strokeWidth="2"
                            />
                            <path d="M -45 -32 L 5 -32 L 30 -15 L -65 -15 Z" fill="#1e293b" stroke="#334155" strokeWidth="1" />
                            <path d="M -85 -5 L -95 -15 L -75 -15" fill={selectedCar.bodyColor} stroke="rgba(0,0,0,0.5)" strokeWidth="2" />
                            <path d="M 70 -8 L 82 0 L 70 5 Z" fill="#fef08a" opacity="0.8" />
                            <path d="M -85 0 L -80 0 L -80 10 L -85 10 Z" fill="#ef4444" stroke="#991b1b" strokeWidth="1" />
                        </>
                    )}

                    {selectedCar.shape === 'buggy' && (
                        <>
                             {/* Roll Cage */}
                             <path d="M -40 -10 L -30 -45 L 30 -45 L 50 -10" fill="none" stroke="#334155" strokeWidth="6" strokeLinecap="round" />
                             <path d="M -30 -45 L 30 -10" fill="none" stroke="#334155" strokeWidth="4" />
                             {/* Body */}
                             <path
                                d="M -70 15 L -75 -5 L -50 -15 L 60 -15 L 80 0 L 75 15 Z"
                                fill={selectedCar.texture && selectedCar.texture !== 'plain' ? "url(#carBodyPattern)" : selectedCar.bodyColor}
                                stroke="rgba(0,0,0,0.5)" strokeWidth="2"
                            />
                            <path d="M 75 -5 L 82 2 L 75 8 Z" fill="#fef08a" opacity="0.8" />
                        </>
                    )}

                    {selectedCar.shape === 'jeep' && (
                        <>
                            {/* Top Box */}
                            <rect x="-50" y="-45" width="70" height="30" fill={selectedCar.bodyColor} stroke="rgba(0,0,0,0.3)" />
                            {/* Window */}
                            <rect x="-45" y="-40" width="30" height="20" fill="#1e293b" />
